from typing import List, Dict, Any


def calculate_grade(score: float) -> str:
    """Calculate letter grade based on score."""
    if score > 90:
        return 'A'
    elif score > 70:
        return 'B'
    else:
        return 'C'


def transform_record(record: Dict[str, Any]) -> Dict[str, Any]:
    """Transform a single record with boosted score and calculated grade."""
    boosted_score = record['score'] * 1.1
    return {
        'name': record['name'].upper(),
        'score': boosted_score,
        'grade': calculate_grade(record['score'])  # Grade based on original score
    }


def is_eligible_record(record: Dict[str, Any]) -> bool:
    """Check if record meets processing criteria."""
    return record.get('status') == 'active' and record.get('score', 0) > 50


def process_data(data: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    """
    Process data by filtering active records with score > 50,
    transforming them with boosted scores and grades, then sorting by score.
    """
    processed_records = [
        transform_record(record)
        for record in data
        if is_eligible_record(record)
    ]

    return sorted(processed_records, key=lambda x: x['score'], reverse=True)
