def process_student_record(record: Dict[str, Any]) -> Dict[str, Any]:
    """Process a single student record with bonus applied."""
    bonus_multiplier = 1.1
    boosted_score = record['score'] * bonus_multiplier

    return {
        'name': record['name'].upper(),
        'score': boosted_score,
        'grade': calculate_grade(record['score'])
    }


def process_data(data: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    """
    Process student data by filtering active students with score > 50,
    applying score bonus, and sorting by score in descending order.
    """
    min_score_threshold = 50

    processed_records = [
        process_student_record(record)
        for record in data
        if record.get('status') == 'active' and record.get('score', 0) > min_score_threshold
    ]

    return sorted(processed_records, key=lambda x: x['score'], reverse=True)
